module top_module(
    q,
    q_n,
    d,
    reset,
    clk
);output q;
    output q_n;
    input d;
    input reset;
    input clk;

    reg q;
    wire q_n;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
        if (!reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

    assign q_n = ~q;

endmodule
